#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelArgmaxOverADimensionCustom {
public:
    __aicore__ inline KernelArgmaxOverADimensionCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t numRows, uint32_t numCols, uint32_t tileRows)
    {
        numRows_ = numRows;
        numCols_ = numCols;
        tileRows_ = tileRows;

        xGm_.SetGlobalBuffer((__gm__ float*)x);
        yGm_.SetGlobalBuffer((__gm__ int32_t*)y);

        uint32_t tileSizeFloats = tileRows_ * numCols_;
        // WholeReduceMax output: tileRows * 2 floats (value + index interleaved)
        uint32_t outSizeFloats = tileRows_ * 2;

        int32_t srcRepeatStride = (numCols_ * sizeof(float) + 31) / 32; // stride in 32B blocks

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileSizeFloats * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileRows_ * sizeof(int32_t));
        pipe_.InitBuffer(reduceOutQueue_, 1, outSizeFloats * sizeof(float));
        // No separate tmp queue needed for WholeReduceMax, but we still need a work buffer? It uses internal workspace.
        // Actually WholeReduceMax does not need a separate workspace tensor; it uses internal registers.
    }

    __aicore__ inline void Process()
    {
        if (numRows_ == 0 || numCols_ == 0) return;

        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());

        uint32_t startRow = blockIdx * tileRows_;
        if (startRow >= numRows_) return;

        while (startRow < numRows_) {
            uint32_t remaining = numRows_ - startRow;
            uint32_t curRows = (remaining > tileRows_) ? tileRows_ : remaining;
            CopyIn(startRow, curRows);
            Compute(curRows);
            CopyOut(startRow, curRows);
            startRow += blockNum * tileRows_;
        }
    }

private:
    __aicore__ inline void CopyIn(uint32_t rowBase, uint32_t rows)
    {
        uint32_t lenFloats = rows * numCols_;
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[rowBase * numCols_], lenFloats);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void Compute(uint32_t rows)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
        AscendC::LocalTensor<int32_t> yLocal = outQueueY_.AllocTensor<int32_t>();
        AscendC::LocalTensor<float> reduceOut = reduceOutQueue_.AllocTensor<float>();

        // Use WholeReduceMax to compute per-row argmax (value and index interleaved)
        int32_t mask = static_cast<int32_t>(numCols_);
        int32_t repeat = static_cast<int32_t>(rows);
        int32_t srcRepeatStride = (numCols_ * sizeof(float) + 31) / 32; // blocks of 32 bytes
        // For WholeReduceMax, srcBlkStride=1, dstBlkStride=1
        AscendC::WholeReduceMax<float>(reduceOut, xLocal, mask, repeat, 1, 1, srcRepeatStride, AscendC::ReduceOrder::ORDER_VALUE_INDEX);

        // Extract indices (odd positions in reduceOut) and cast to int32
        for (uint32_t r = 0; r < rows; ++r) {
            float idxFloat = reduceOut.GetValue(2 * r + 1);
            yLocal.SetValue(r, static_cast<int32_t>(idxFloat));
        }

        reduceOutQueue_.FreeTensor(reduceOut);
        outQueueY_.EnQue<int32_t>(yLocal);
        inQueueX_.FreeTensor(xLocal);
    }

    __aicore__ inline void CopyOut(uint32_t rowBase, uint32_t rows)
    {
        AscendC::LocalTensor<int32_t> yLocal = outQueueY_.DeQue<int32_t>();
        AscendC::DataCopy(yGm_[rowBase], yLocal, rows);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECOUT, 1> reduceOutQueue_;
    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<int32_t> yGm_;
    uint32_t numRows_ {0};
    uint32_t numCols_ {0};
    uint32_t tileRows_ {0};
};

